def gen(rng, size):
    def build(limit):
        count = [0]
        idx = [0]
        def rec():
            if count[0] >= limit or rng.random() < 0.35:
                return None
            count[0] += 1
            v = rng.randint(-20, 20)
            node = {'v': v, 'l': None, 'r': None}
            node['l'] = rec()
            node['r'] = rec()
            return node
        root = rec()
        if root is None:
            root = {'v': rng.randint(-20, 20), 'l': None, 'r': None}
        return root
    big = build(max(1, min(size, 60)))
    # collect all subtree roots
    subs = []
    stack = [big]
    while stack:
        nd = stack.pop()
        if nd is None:
            continue
        subs.append(nd)
        stack.append(nd['l']); stack.append(nd['r'])
    if rng.random() < 0.5 and subs:
        target = rng.choice(subs)
    else:
        target = build(max(1, min(size // 3 + 1, 20)))
    def serialize(root):
        out = []
        from collections import deque
        q = deque([root])
        while q:
            nd = q.popleft()
            if nd is None:
                out.append(None); continue
            out.append(nd['v'])
            q.append(nd['l']); q.append(nd['r'])
        while out and out[-1] is None:
            out.pop()
        return out
    return [serialize(big), serialize(target)]

