class Solution:
    def isSubtree(self, root, subRoot):
        def serial(node):
            if not node:
                return '#'
            return '(' + str(node.val) + serial(node.left) + serial(node.right) + ')'
        target = serial(subRoot)
        nodes = []
        stack = [root]
        while stack:
            nd = stack.pop()
            if not nd:
                continue
            nodes.append(nd)
            stack.append(nd.left); stack.append(nd.right)
        for nd in nodes:
            if serial(nd) == target:
                return True
        return False

